fn fb_bg(p: vec2f, t: f32) -> vec3f {
  // the unlensed sky: nebula, dust, two starfield depths
  var c = vec3f(0.010, 0.008, 0.022);

  // nebula — indigo body, rose folds, gold filaments
  let q = p * 1.6 + vec2f(0.3, -0.2);
  let n1 = fbm(q + vec2f(t * 0.004, 0.0), 5);
  let n2 = fbm(q * 2.3 + vec2f(7.0, 3.0) - vec2f(0.0, t * 0.003), 4);
  c += vec3f(0.10, 0.05, 0.28) * smoothstep(0.35, 0.85, n1) * 1.1;
  c += vec3f(0.30, 0.08, 0.22) * smoothstep(0.55, 0.9, n1 * 0.6 + n2 * 0.6) * 0.9;
  c += vec3f(0.55, 0.38, 0.12) * pow(smoothstep(0.62, 0.95, n2), 2.0) * 0.8;
  // dark dust lane
  c *= 1.0 - 0.55 * smoothstep(0.55, 0.8, fbm(q * 1.3 + vec2f(21.0, 13.0), 4));

  // stars — two depths, hue-varied, twinkling
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (14.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let h2 = hash21(cell + 91.0);
    let fp = fract(sp) - 0.5 + (vec2f(h, h2) - 0.5) * 0.6;
    let star = step(0.982 - fl * 0.006, h) * smoothstep(0.24, 0.02, length(fp));
    let tw = 0.55 + 0.45 * sin(t * (0.6 + h * 1.6) + h * 40.0);
    let hue = mix(vec3f(0.75, 0.82, 1.05), vec3f(1.05, 0.85, 0.6), h2);
    c += hue * star * tw * (1.4 - fl * 0.5);
  }
  return c;
}

fn fb_mass(i: i32) -> vec3f { return vec3f(uni(9 + i * 3), uni(10 + i * 3), uni(11 + i * 3)); }

// total lens deflection: sample the sky at beta = theta - sum(m_i * d_i / r_i^2)
fn fb_beta(uv: vec2f, mScale: f32, t: f32) -> vec2f {
  var beta = uv;
  let nA = i32(uni(0));
  for (var i = 0; i < 9; i++) {
    if (i >= nA) { break; }
    let m = fb_mass(i);
    let d = uv - m.xy;
    let r2 = max(dot(d, d), 0.0004);
    beta -= d * (m.z * mScale) / r2;
  }
  // the cursor lens
  let md = uv - vec2f(uni(1), uni(2));
  let mr2 = max(dot(md, md), 0.0004);
  beta -= md * (uni(3) * mScale) / mr2;
  // gravitational ripple from the last anchor drop
  let rt = uni(6);
  if (rt < 4.0) {
    let ro = uv - vec2f(uni(7), uni(8));
    let rr = length(ro);
    let wave = sin((rr - rt * 0.9) * 26.0) * exp(-pow((rr - rt * 0.9) * 3.2, 2.0)) * exp(-rt * 1.1);
    beta += (ro / max(rr, 0.01)) * wave * 0.02;
  }
  return beta;
}

fn visual_fb_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let chroma = uni(5) * 0.22;

  // lensed sky, with dispersion: each color feels gravity slightly differently
  let bR = fb_beta(uv, 1.0 - chroma, t);
  let bG = fb_beta(uv, 1.0, t);
  let bB = fb_beta(uv, 1.0 + chroma, t);
  var col = vec3f(fb_bg(bR, t).r, fb_bg(bG, t).g, fb_bg(bB, t).b);

  // spacetime grid, drawn in SOURCE coordinates — lines funnel into the wells
  let g01 = uni(4);
  if (g01 > 0.01) {
    let gc = bG * 7.0;
    let gx = smoothstep(0.06, 0.0, abs(fract(gc.x) - 0.5) - 0.44);
    let gy = smoothstep(0.06, 0.0, abs(fract(gc.y) - 0.5) - 0.44);
    col += vec3f(0.10, 0.22, 0.28) * max(gx, gy) * g01 * 0.8;
  }

  // the masses themselves: dark cores wearing hot photon rings
  let nA = i32(uni(0));
  for (var i = 0; i < 10; i++) {
    var m: vec3f;
    var held = false;
    if (i < nA) { m = fb_mass(i); }
    else if (i == nA) { m = vec3f(uni(1), uni(2), uni(3)); held = true; }
    else { break; }
    if (m.z < 0.0005) { continue; }
    let r = length(uv - m.xy);
    let rs = sqrt(m.z) * 0.55;                 // event-horizon scale from the Einstein radius
    col = mix(col, vec3f(0.0), smoothstep(rs, rs * 0.55, r));
    var ringCol = vec3f(3.2, 2.1, 1.0);
    if (held) { ringCol = vec3f(1.2, 2.6, 3.2); }
    let flick = 0.85 + 0.15 * sin(t * 5.0 + f32(i) * 9.0 + r * 40.0);
    col += ringCol * exp(-pow((r - rs * 1.18) * (34.0 / max(rs, 0.02)) * rs, 2.0) * 3.0) * flick;
    // faint accretion shimmer just outside the ring
    let sh = exp(-pow((r - rs * 1.7) * 8.0 / max(rs, 0.05), 2.0));
    col += vec3f(0.5, 0.3, 0.15) * sh * (0.4 + 0.3 * sin(t * 1.3 + atan2(uv.y - m.y, uv.x - m.x + 1e-5) * 3.0 - t));
  }

  // NaN scrub — nothing poisoned may reach the bloom
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01, 0.01, 0.02); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(4), uni(5));     // cursor (uv coords)
  let cam = vec2f(uni(0), uni(1));
  let zm = uni(2);

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── the bubble universe: live positions, pressure-ranked, explorable ──
  for (var i = 0; i < i32(uni(3) + 0.5); i++) {
    let sv = uni(8 + i * 3);
    let st = i32(floor(sv));
    let hue = fract(sv);
    let ctr = vec2f((uni(6 + i * 3) - cam.x) * zm / 256.0, (uni(7 + i * 3) - cam.y) * zm / 256.0);
    let d = length(uv - ctr);
    let R = 0.098 * zm;
    let hov = smoothstep(R * 1.9, R * 1.1, length(mp - ctr));
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

const HL_HOR: f32 = 336.0;

fn hl_moonness(ph: f32) -> f32 { return 0.5 - 0.5 * cos(6.2831853 * ph); }

// sky + orb, callable so the lake can mirror it
fn hl_sky(p: vec2f, sun: vec2f, m: f32, t: f32, a: f32) -> vec3f {
  let up = clamp(1.0 - p.y / HL_HOR, 0.0, 1.0);
  // day palette → night palette
  let dayZen = vec3f(0.16, 0.34, 0.62);
  let dayHor = vec3f(0.95, 0.62, 0.32);
  let nightZen = vec3f(0.015, 0.020, 0.055);
  let nightHor = vec3f(0.05, 0.06, 0.13);
  var col = mix(mix(dayHor, dayZen, pow(up, 0.6)), mix(nightHor, nightZen, pow(up, 0.6)), m);

  // light breathes from wherever the orb is (screen-round despite the
  // vertical compression that fits the painting to wide viewports)
  let rel = vec2f(p.x - sun.x, (p.y - sun.y) / a);
  let d = length(rel);
  let warm = mix(vec3f(1.1, 0.7, 0.35), vec3f(0.55, 0.62, 0.80), m);
  col += warm * exp(-d * 0.012) * mix(0.5, 0.28, m);

  // the orb: gold sun ↔ silver moon with craters and a crescent bite
  let r = 26.0;
  if (d < r) {
    var oc = mix(vec3f(3.2, 2.4, 1.1), vec3f(1.6, 1.7, 1.9), m);
    // craters surface only as it becomes moon
    let cr = vnoise(rel * 0.22 + 7.0);
    oc *= 1.0 - m * 0.35 * smoothstep(0.45, 0.8, cr);
    // crescent: a dark disk slides across as moonness grows past half
    let bite = length(rel - vec2f(r * 0.85 * smoothstep(0.35, 1.0, m), -4.0));
    if (m > 0.35 && bite < r * 0.98) { oc *= 0.12; }
    col = oc;
  }
  col += warm * exp(-max(d - r, 0.0) * 0.05) * mix(0.9, 0.55, m);   // corona

  // stars belong to the moon
  if (m > 0.25) {
    let sp2 = p * 0.14;
    let cell = floor(sp2);
    let st = hash21(cell);
    if (st > 0.975 && p.y < HL_HOR - 10.0) {
      let d2 = length(fract(sp2) - 0.5);
      let tw = 0.5 + 0.5 * sin(t * 3.0 + st * 40.0);
      col += vec3f(0.9, 0.92, 1.0) * smoothstep(0.16, 0.02, d2) * tw * smoothstep(0.25, 0.6, m);
    }
  }
  return col;
}

fn hl_ridge(x: f32, seed: f32, amp: f32, base: f32) -> f32 {
  return base - amp * (fbm3(vec2f(x * 0.008 + seed, seed)) - 0.25);
}

fn visual_helios(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let asp = 1.0;   // contain-fit shows the whole painting
  let p = vec2f((uv.x + 1.0) * 256.0, (uv.y * asp + 1.0) * 256.0);
  let t = time;
  var sun = vec2f(uni(0), uni(1));
  if (sun.x < 1.0) { sun = vec2f(150.0, 120.0); }        // pre-hook default: morning
  let m = hl_moonness(uni(2));
  let gold = uni(4);

  var col: vec3f;
  let LAKE = 424.0;

  if (p.y < LAKE) {
    col = hl_sky(p, sun, m, t, asp);

    // three ridgelines, lit from wherever the orb hangs
    let warm = mix(vec3f(1.0, 0.75, 0.45), vec3f(0.5, 0.58, 0.75), m);
    let sunSide = clamp(1.0 - abs(p.x - sun.x) / 360.0, 0.0, 1.0);
    let r1 = hl_ridge(p.x, 3.0, 90.0, HL_HOR - 40.0);
    let r2 = hl_ridge(p.x, 11.0, 60.0, HL_HOR - 6.0);
    let r3 = hl_ridge(p.x, 27.0, 34.0, HL_HOR + 26.0);
    if (p.y > r3 && p.y < LAKE) {
      col = mix(vec3f(0.10, 0.16, 0.08), vec3f(0.012, 0.02, 0.03), m);
      col += warm * 0.35 * sunSide * smoothstep(r3 + 14.0, r3, p.y);  // lit brow
      col *= 0.9 + 0.2 * vnoise(p * 0.12);
    } else if (p.y > r2) {
      col = mix(vec3f(0.13, 0.20, 0.11), vec3f(0.02, 0.03, 0.05), m);
      col += warm * 0.30 * sunSide * smoothstep(r2 + 12.0, r2, p.y);
      col *= 0.9 + 0.2 * vnoise(p * 0.1 + 5.0);
    } else if (p.y > r1) {
      col = mix(vec3f(0.17, 0.25, 0.15), vec3f(0.03, 0.045, 0.07), m);
      col += warm * 0.28 * sunSide * smoothstep(r1 + 10.0, r1, p.y);
      col *= 0.9 + 0.2 * vnoise(p * 0.08 + 9.0);
    }

    // fireflies rise at night over the near meadow
    if (m > 0.5 && p.y > HL_HOR) {
      let fp2 = p * 0.06 + vec2f(0.0, t * 0.06);
      let fc = floor(fp2);
      let fh = hash21(fc + 31.0);
      if (fh > 0.955) {
        let fd = length(fract(fp2) - 0.5);
        let blink = pow(0.5 + 0.5 * sin(t * 2.5 + fh * 60.0), 3.0);
        col += vec3f(0.9, 1.4, 0.3) * smoothstep(0.10, 0.02, fd) * blink * (m - 0.5) * 2.4;
      }
    }
  } else {
    // the lake: the whole sky again, upside down and breathing
    let ry = LAKE - (p.y - LAKE) * 1.9;
    let wob = vnoise(vec2f(p.x * 0.05, p.y * 0.3 - t * 0.8)) - 0.5;
    var rp = vec2f(p.x + wob * 9.0, ry + wob * 5.0);
    col = hl_sky(rp, sun, m, t, asp) * mix(0.62, 0.5, m);
    col += vec3f(0.04, 0.05, 0.06) * (0.5 + wob);

    // moon-glitter: when the moon is out and its face lies on the lake,
    // the water sparkles along the reflection path
    let refY = LAKE + (LAKE - sun.y) / 1.9;
    let mglow = smoothstep(0.35, 0.75, m) * smoothstep(620.0, 500.0, refY);
    if (mglow > 0.01) {
      let depth = clamp((p.y - LAKE) / (512.0 - LAKE), 0.0, 1.0);
      let spread = 16.0 + 100.0 * depth;                 // the glade widens toward you
      let path = smoothstep(spread, spread * 0.2, abs(p.x - sun.x + wob * 14.0));
      // glint cells — little horizontal flecks, twinkling out of phase
      let gp = vec2f(p.x * 0.12, p.y * 0.3 - t * 0.55);
      let gh = hash21(floor(gp));
      let gd = length((fract(gp) - 0.5) * vec2f(0.9, 2.2));
      let flash = pow(0.5 + 0.5 * sin(t * (2.0 + gh * 6.0) + gh * 47.0), 6.0);
      let glint = smoothstep(0.45, 0.05, gd) * step(0.80, gh) * flash;
      col += vec3f(1.05, 1.12, 1.30) * glint * path * mglow * 2.8;   // the sparkle
      col += vec3f(0.35, 0.40, 0.55) * path * mglow * 0.20 * (0.6 + wob);  // silver sheen
      col += vec3f(1.30, 0.95, 0.40) * path * gold * 0.55 * (0.7 + wob);   // the invitation
    }
  }

  // hold feedback: a slow pulse ring while the orb is aging
  if (uni(3) > 0.01) {
    let ring = abs(length(vec2f(p.x - sun.x, (p.y - sun.y) / asp)) - (30.0 + fract(t * 0.8) * 26.0));
    col += vec3f(0.8, 0.8, 0.7) * uni(3) * smoothstep(3.0, 0.0, ring) * 0.5;
  }

  // the moon's reflection noticed you: the whole valley breathes gold
  if (gold > 0.01) {
    let breath = 0.5 + 0.5 * sin(t * 3.2);
    col += vec3f(1.05, 0.78, 0.28) * gold * (0.10 + 0.11 * breath) * (1.25 - 0.5 * length(uv));
  }

  col *= 1.0 - 0.35 * pow(length(uv), 3.0);
  return vec4f(col, 1.0);
}

fn visual_helios_grove(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
